import json,sys,urllib.request,time,copy
from collections import Counter
K=sys.argv[1]; B='https://irynakarmazina.app.n8n.cloud/api/v1/'
def call(method,u,data=None):
    h={'X-N8N-API-KEY':K}
    if data is not None: h['Content-Type']='application/json'
    for a in range(8):
        try:
            r=urllib.request.urlopen(urllib.request.Request(B+u,data=data,method=method,headers=h),timeout=20); return r.status,r.read()
        except Exception as e: time.sleep(3)
    return None,b''
mk=json.load(open('/root/mk-backup-JQKA35haUsXU4XqE.json'))
readn=[n for n in mk['nodes'] if n.get('name')=='Читаємо CRM'][0]
rn=copy.deepcopy(readn); rn['name']='Read'; rn['id']='r1'; rn['position']=[220,0]
fjs="const rows=$input.all().map(i=>i.json); const u=rows.map(r=>String(r['Угода']||'').trim()).filter(x=>x); return [{json:{total:rows.length, uniq:new Set(u).size, all:u}}];"
filt={'parameters':{'jsCode':fjs},'name':'Filter','type':'n8n-nodes-base.code','typeVersion':2,'position':[440,0],'id':'f1'}
resp={'parameters':{'respondWith':'json','responseBody':'={{ JSON.stringify($json) }}','options':{}},'name':'Respond','type':'n8n-nodes-base.respondToWebhook','typeVersion':1,'position':[680,0],'id':'rp1'}
wf={'name':'ONESHOT verify-count (Claude)','nodes':[{'parameters':{'httpMethod':'POST','path':'claude-verify-count','responseMode':'responseNode','options':{}},'name':'Trigger','type':'n8n-nodes-base.webhook','typeVersion':2,'position':[0,0],'id':'t1','webhookId':'claude-verify-count'},rn,filt,resp],'connections':{'Trigger':{'main':[[{'node':'Read','type':'main','index':0}]]},'Read':{'main':[[{'node':'Filter','type':'main','index':0}]]},'Filter':{'main':[[{'node':'Respond','type':'main','index':0}]]}},'settings':{'executionOrder':'v1'}}
st,body=call('POST','workflows',json.dumps(wf).encode())
wid=json.loads(body).get('id') if st in (200,201) else None
print('created',wid)
if wid:
    call('POST','workflows/'+wid+'/activate'); time.sleep(4)
    import urllib.request as U
    try:
        r=U.urlopen(U.Request('https://irynakarmazina.app.n8n.cloud/webhook/claude-verify-count',data=b'{}',method='POST',headers={'Content-Type':'application/json'}),timeout=90)
        res=json.loads(r.read().decode('utf-8','ignore'))
        json.dump(res.get('all',[]), open('/root/sheet-uhody-backup.json','w'))
        c=Counter(res.get('all',[])); dups=[k for k,v in c.items() if v>1]
        print('total rows:',res.get('total'),'| унікальних Угод:',res.get('uniq'),'| ДУБЛІКАТИ:',dups[:20],'(к-ть',len(dups),')')
    except Exception as e: print('err',e)
    call('DELETE','workflows/'+wid); print('deleted')

PYEOF
